#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



float error     = 0.5;        // maximum random pixel offset
float diffusion = 0.004;      // dither strength
float fadeout   = -0.0015;    // may be minor 1/256 due to the error diffusion dither;

vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw*1.5 + rand_frame.xy;
float magic = lum(GetPixel(mix(vUvOriginal,vUv, 8))) - lum(GetBlur1(mix(vUvOriginal,vUv,-8)));
vUv = mix(vUvOriginal,vUv, magic*0.75 ) + (texture(sampler_noise_lq, dither_uv)-0.5)*uTexSize.zw*error;
ret = GetPixel(vUv)+(texture(sampler_noise_lq, dither_uv)-0.5)*diffusion + fadeout;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 d = uTexSize.zw;
float cutoff = 0.02;
vec3 dx = clamp01(GetPixel(vUv + vec2(1,0)*d)-cutoff) - clamp01(GetPixel(vUv + vec2(-1,0)*d)-cutoff);
vec3 dy = clamp01(GetPixel(vUv + vec2(0,1)*d)-cutoff) - clamp01(GetPixel(vUv + vec2(0,-1)*d)-cutoff);
vec3 gx = length(vec2(dx.x, dy.x));
d = uTexSize.zw*3;
dx = GetBlur1(vUv + vec2(1,0)*d) - GetBlur1(vUv + vec2(-1,0)*d);
dy = GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv + vec2(0,-1)*d);
vec2 uv1 = fract(vUv + vec2(dx.x,dy.x) - vec2(dx.y,dy.y)*2 );
vec2 uv2 = fract(vUv - vec2(dx.z,dy.z)*0.0 );
vec2 uv3 = fract(vUv + vec2(dx.y,dy.y)*0.01 - vec2(dx.x,dy.x)*0.2);
ret = mix(ret,vec3(0.9,1,2),GetPixel(uv1).z);
ret = mix(ret,vec3(1,0,0),GetPixel(vUv).x);
ret = mix(ret,2.4, gx*(1+audioHigh));
ret = mix(ret,1,GetBlur2(uv2).z*GetPixel(vUv).x);
ret = mix(ret,vec3(1.2,1.2,0),GetPixel(uv3).y*0.8);

  fragColor = ret;
}
